import React, { useState, useEffect, useRef } from 'react'
import { trackPromise } from 'react-promise-tracker'
import {
  CCardHeader,
  CButton,
  CCard,
  CCardBody,
  CTable,
  CTableHead,
  CTableRow,
  CTableHeaderCell,
  CTableBody,
  CTableDataCell,
  CBadge,
  CSpinner,
  CToaster,
} from '@coreui/react'
import { getUser } from 'src/utils/Auth'
import axios from 'axios'
import Notify from 'src/utils/Notify'
import Receipt from 'src/utils/Receipt'
import LoadingIndicator from 'src/utils/LoadingIndicator'

const Payments = () => {
  const [payments, setPayments] = useState([])
  const [loading, setLoading] = useState(null)
  const [error, setError] = useState(false)
  const [toast, addToast] = useState(0)
  const [message, setMessage] = useState(null)
  const toaster = useRef()
  const [visible, setVisible] = useState(false)
  const [receiptDetails, setReceiptDetails] = useState({})

  const user = getUser()

  useEffect(() => {
    const getPaymentStat = async () => {
      const resFromServer = await fetchStat()
      resFromServer ? setPayments(resFromServer) : setPayments(null)
    }
    getPaymentStat()
  }, [])

  useEffect(() => {
    if (message) addToast(notify)
  }, [message])

  const notify = <Notify error={error} message={message} />

  const fetchStat = async () => {
    const res = await trackPromise(
      fetch(
        `https://records.run.edu.ng/api/app/my_payments?userid=${user.id}&matno=${user.matric_number}`,
      ),
    )
    const data = await res.json()
    return data
  }

  const handleReceipt = (amount, rrr, created_at, destination) => {
    setVisible(true)
    setReceiptDetails((prevState) => ({
      ...prevState,
      amount: amount,
      rrr: rrr,
      created_at: created_at,
      destination: destination,
    }))
    console.log(receiptDetails)
  }

  const handleRequery = (rrr, i) => {
    setLoading(i)
    setMessage(null)
    setError(null)
    axios
      .post('https://records.run.edu.ng/api/app/re_query_transaction', {
        rrr: rrr,
      })
      .then(function (response) {
        console.log(response)
        setLoading(null)
        setMessage(response.data.message)
      })
      .catch((err) => {
        setLoading(null)
        setError(true)
        if (err.response) {
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  return (
    <>
      <CCard className="mb-4">
        <CCardHeader>Transaction History</CCardHeader>
        <CCardBody>
          <CTable align="middle" className="mb-0 border" hover responsive>
            <CTableHead color="dark">
              <CTableRow>
                <CTableHeaderCell>S/N</CTableHeaderCell>
                <CTableHeaderCell>Transaction ID</CTableHeaderCell>
                <CTableHeaderCell className="text-center">Amount</CTableHeaderCell>
                <CTableHeaderCell>Description</CTableHeaderCell>
                <CTableHeaderCell className="text-center">Date</CTableHeaderCell>
                <CTableHeaderCell className="text-center">Status</CTableHeaderCell>
                <CTableHeaderCell>Action</CTableHeaderCell>
              </CTableRow>
            </CTableHead>
            {payments ? (
              <CTableBody>
                {payments.map((item, index) => (
                  <CTableRow v-for="item in tableItems" key={index}>
                    <CTableDataCell>{index + 1}</CTableDataCell>
                    <CTableDataCell>
                      <div>{item.rrr}</div>
                    </CTableDataCell>
                    <CTableDataCell className="text-center">
                      <div>{item.amount}</div>
                    </CTableDataCell>
                    <CTableDataCell>
                      <div>{item.destination}</div>
                    </CTableDataCell>
                    <CTableDataCell className="text-center">
                      <div>{new Date(item.created_at).toDateString()}</div>
                    </CTableDataCell>
                    <CTableDataCell className="text-center">
                      {item.status_msg === 'success' ? (
                        <CBadge color="success" shape="rounded-pill">
                          {item.status_msg}
                        </CBadge>
                      ) : (
                        <CBadge color="danger" shape="rounded-pill">
                          {item.status_msg}
                        </CBadge>
                      )}
                    </CTableDataCell>
                    <CTableDataCell>
                      <strong>
                        {item.status_msg === 'success' ? (
                          <CButton
                            color="success"
                            className="px-4"
                            onClick={() =>
                              handleReceipt(
                                item.amount,
                                item.rrr,
                                item.created_at,
                                item.destination,
                              )
                            }
                          >
                            Print
                          </CButton>
                        ) : (
                          <CButton
                            color="danger"
                            className="px-4"
                            disabled={loading === index}
                            onClick={() => handleRequery(item.rrr, index)}
                          >
                            {loading === index && (
                              <CSpinner
                                component="span"
                                size="sm"
                                color="light"
                                variant="grow"
                                aria-hidden="true"
                              />
                            )}{' '}
                            Requery
                          </CButton>
                        )}
                      </strong>
                    </CTableDataCell>
                  </CTableRow>
                ))}
              </CTableBody>
            ) : (
              <LoadingIndicator />
            )}

            <LoadingIndicator />
          </CTable>
        </CCardBody>
      </CCard>
      <CToaster ref={toaster} push={toast} placement="top-end" />
      <Receipt
        visible={visible}
        onClose={() => setVisible(false)}
        amount={receiptDetails.amount}
        rrr={receiptDetails.rrr}
        date={new Date(receiptDetails.created_at).toDateString()}
        desc={receiptDetails.destination}
      />
    </>
  )
}

export default Payments
